12	# ImageCropper
13	
14	An `ImageCropper` lets the user select a rectangular (or circular) region of an image
15	for cropping. It supports drag-to-move, handle-resize, aspect ratio constraints, and
16	zoom/rotation.
17	
18	The following types define the crop data model:
19	
20	```rust
21	/// The crop area in normalized coordinates [0.0, 1.0] relative to the image.
22	#[derive(Clone, Copy, Debug, PartialEq)]
23	pub struct CropArea {
24	    /// Left edge as a fraction of image width.
25	    pub x: f64,
26	    /// Top edge as a fraction of image height.
27	    pub y: f64,
28	    /// Width as a fraction of image width.
29	    pub width: f64,
30	    /// Height as a fraction of image height.
31	    pub height: f64,
32	    /// Rotation in degrees.
33	    pub rotation: f64,
34	}
35	
36	impl Default for CropArea {
37	    fn default() -> Self {
38	        Self { x: 0.1, y: 0.1, width: 0.8, height: 0.8, rotation: 0.0 }
39	    }
40	}
41	
42	/// Which handle of the crop area the user is interacting with.
43	#[derive(Clone, Copy, Debug, PartialEq, Eq)]
44	pub enum CropHandle {
45	    TopLeft,
46	    TopRight,
47	    BottomLeft,
48	    BottomRight,
49	    Top,
50	    Bottom,
51	    Left,
52	    Right,
53	}
54	
55	/// Aspect ratio constraint for the crop area.
56	#[derive(Clone, Copy, Debug, PartialEq)]
57	pub enum AspectRatio {
58	    /// No constraint.
59	    Free,
60	    /// Fixed width:height ratio.
61	    Fixed(f64),
62	    /// 1:1 square.
63	    Square,
64	    /// 4:3 landscape.
65	    Landscape4x3,
66	    /// 3:4 portrait.
67	    Portrait3x4,
68	    /// 16:9 wide.
69	    Wide16x9,
70	}
71	
72	impl AspectRatio {
73	    /// Get the ratio as a float.
74	    pub fn as_ratio(&self) -> Option<f64> {
75	        match self {
76	            Self::Free => None,
77	            Self::Fixed(r) => Some(*r),
78	            Self::Square => Some(1.0),
79	            Self::Landscape4x3 => Some(4.0 / 3.0),
80	            Self::Portrait3x4 => Some(3.0 / 4.0),
81	            Self::Wide16x9 => Some(16.0 / 9.0),
82	        }
83	    }
84	}
85	
86	/// Output format for the cropped image.
87	#[derive(Clone, Copy, Debug, PartialEq, Eq)]
88	pub enum CropOutputFormat {
89	    /// PNG format.
90	    Png,
91	    /// JPEG format.
92	    Jpeg { quality: u8 },
93	    /// WebP format.
94	    WebP { quality: u8 },
95	}
96	
97	/// Flip state for the image.
98	#[derive(Clone, Copy, Debug, Default, PartialEq, Eq)]
99	pub struct FlipState {
100	    /// Horizontal flip.
101	    pub horizontal: bool,
102	    /// Vertical flip.
103	    pub vertical: bool,
104	}
105	
106	/// Result of a crop operation.
107	///
108	/// All coordinates are normalized to [0.0, 1.0] relative to the original
109	/// image dimensions. This allows the crop to be applied server-side
110	/// regardless of the display size used during cropping.
111	#[derive(Clone, Copy, Debug, PartialEq)]
112	pub struct CropResult {
113	    /// Left edge as a fraction of original image width.
114	    pub x: f64,
115	    /// Top edge as a fraction of original image height.
116	    pub y: f64,
117	    /// Width as a fraction of original image width.
118	    pub width: f64,
119	    /// Height as a fraction of original image height.
120	    pub height: f64,
121	    /// Rotation in degrees applied to the image before cropping.
122	    pub rotation: f64,
123	    /// Scale factor applied (1.0 = no zoom).
124	    pub scale: f64,
125	    /// Aspect ratio constraint if one was active (e.g., `Some(16.0 / 9.0)`).
126	    pub aspect_ratio: Option<f64>,
127	    /// Flip state applied to the image.
128	    pub flip: FlipState,
129	}
130	
131	impl CropResult {
132	    /// Build a `CropResult` from a `CropArea` and current zoom/aspect/flip state.
133	    pub fn from_crop_area(area: &CropArea, zoom: f64, aspect: &AspectRatio, flip: FlipState) -> Self {
134	        CropResult {
135	            x: area.x,
136	            y: area.y,
137	            width: area.width,
138	            height: area.height,
139	            rotation: area.rotation,
140	            scale: zoom,
141	            aspect_ratio: aspect.as_ratio(),
142	            flip,
143	        }
144	    }
145	}
146	```
147	
148	## 1. State Machine
149	
150	### 1.1 States
151	
152	```rust
153	/// The states for the `ImageCropper` component.
154	#[derive(Clone, Copy, Debug, PartialEq, Eq)]
155	pub enum State {
156	    /// Image loaded, crop area visible, not interacting.
157	    Idle,
158	    /// User is dragging the crop area to move it.
159	    Dragging,
160	    /// User is resizing via a handle.
161	    Resizing {
162	        /// The handle the user is resizing.
163	        handle: CropHandle,
164	    },
165	}
166	```
167	
168	### 1.2 Events
169	
170	```rust
171	/// The events for the `ImageCropper` component.
172	#[derive(Clone, Copy, Debug, PartialEq)]
173	pub enum Event {
174	    /// Start dragging the crop area.
175	    DragStart { x: f64, y: f64 },
176	    /// Move while dragging.
177	    DragMove { x: f64, y: f64 },
178	    /// End dragging.
179	    DragEnd,
180	    /// Start resizing from a handle.
181	    ResizeStart { handle: CropHandle, x: f64, y: f64 },
182	    /// Move while resizing.
183	    ResizeMove { x: f64, y: f64 },
184	    /// End resizing.
185	    ResizeEnd,
186	    /// Set the crop area directly.
187	    SetCropArea(CropArea),
188	    /// Set the aspect ratio constraint.
189	    SetAspectRatio(AspectRatio),
190	    /// Set zoom level.
191	    SetZoom(f64),
192	    /// Set rotation.
193	    SetRotation(f64),
194	    /// Flip the image horizontally.
195	    FlipHorizontal,
196	    /// Flip the image vertically.
197	    FlipVertical,
198	    /// Reset to default crop area.
199	    Reset,
200	    /// Focus entered a part.
201	    Focus { part: &'static str },
202	    /// Focus left a part.
