270	    /// Initial flip state.
271	    pub flip: FlipState,
272	    /// Disabled state.
273	    pub disabled: bool,
274	}
275	
276	impl Default for Props {
277	    fn default() -> Self {
278	        Self {
279	            id: String::new(),
280	            crop: None,
281	            default_crop: CropArea::default(),
282	            src: String::new(),
283	            aspect_ratio: AspectRatio::Free,
284	            zoom: 1.0,
285	            min_zoom: 1.0,
286	            max_zoom: 3.0,
287	            circular: false,
288	            flip: FlipState::default(),
289	            disabled: false,
290	        }
291	    }
292	}
293	```
294	
295	### 1.5 Full Machine Implementation
296	
297	```rust
298	/// Resize the crop area based on handle position and pointer delta.
299	/// Enforces aspect ratio constraints and boundary clamping.
300	fn resize_crop_area(ctx: &mut Context, handle: CropHandle, x: f64, y: f64) {
301	    if let (Some((ox, oy)), Some(ref start)) = (ctx.drag_origin, &ctx.drag_start_crop) {
302	        let dx = x - ox;
303	        let dy = y - oy;
304	        let mut crop = *start;
305	
306	        match handle {
307	            CropHandle::TopLeft => {
308	                crop.x = (start.x + dx).clamp(0.0, start.x + start.width - 0.05);
309	                crop.y = (start.y + dy).clamp(0.0, start.y + start.height - 0.05);
310	                crop.width = start.width - (crop.x - start.x);
311	                crop.height = start.height - (crop.y - start.y);
312	            }
313	            CropHandle::TopRight => {
314	                crop.y = (start.y + dy).clamp(0.0, start.y + start.height - 0.05);
315	                crop.width = (start.width + dx).clamp(0.05, 1.0 - start.x);
316	                crop.height = start.height - (crop.y - start.y);
317	            }
318	            CropHandle::BottomLeft => {
319	                crop.x = (start.x + dx).clamp(0.0, start.x + start.width - 0.05);
320	                crop.width = start.width - (crop.x - start.x);
321	                crop.height = (start.height + dy).clamp(0.05, 1.0 - start.y);
322	            }
323	            CropHandle::BottomRight => {
324	                crop.width = (start.width + dx).clamp(0.05, 1.0 - start.x);
325	                crop.height = (start.height + dy).clamp(0.05, 1.0 - start.y);
326	            }
327	            CropHandle::Top => {
328	                crop.y = (start.y + dy).clamp(0.0, start.y + start.height - 0.05);
329	                crop.height = start.height - (crop.y - start.y);
330	            }
331	            CropHandle::Bottom => {
332	                crop.height = (start.height + dy).clamp(0.05, 1.0 - start.y);
333	            }
334	            CropHandle::Left => {
335	                crop.x = (start.x + dx).clamp(0.0, start.x + start.width - 0.05);
336	                crop.width = start.width - (crop.x - start.x);
337	            }
338	            CropHandle::Right => {
339	                crop.width = (start.width + dx).clamp(0.05, 1.0 - start.x);
340	            }
341	        }
342	
343	        // Enforce aspect ratio if set
344	        if let Some(ratio) = ctx.aspect_ratio.as_ratio() {
345	            crop.height = crop.width / ratio;
346	            // Re-clamp after aspect ratio enforcement
347	            if crop.y + crop.height > 1.0 {
348	                crop.height = 1.0 - crop.y;
349	                crop.width = crop.height * ratio;
350	            }
351	        }
352	
353	        ctx.crop.set(crop);
354	    }
355	}
356	
357	/// Re-constrain the current crop area to match the current aspect ratio.
358	fn enforce_aspect_ratio(ctx: &mut Context) {
359	    if let Some(ratio) = ctx.aspect_ratio.as_ratio() {
360	        let mut crop = ctx.crop.get();
361	        crop.height = crop.width / ratio;
362	        if crop.y + crop.height > 1.0 {
363	            crop.height = 1.0 - crop.y;
364	            crop.width = crop.height * ratio;
365	        }
366	        ctx.crop.set(crop);
367	    }
368	}
369	
370	/// The machine for the `ImageCropper` component.
371	pub struct Machine;
372	
373	impl ars_core::Machine for Machine {
374	    type State = State;
375	    type Event = Event;
376	    type Context = Context;
377	    type Props = Props;
378	    type Messages = Messages;
379	    type Api<'a> = Api<'a>;
380	
381	    fn init(props: &Self::Props, env: &Env, messages: &Self::Messages) -> (Self::State, Self::Context) {
382	        let crop = match &props.crop {
383	            Some(c) => Bindable::controlled(*c),
384	            None => Bindable::uncontrolled(props.default_crop),
385	        };
386	
387	        let ids = ComponentIds::from_id(&props.id);
388	        let locale = env.locale.clone();
389	        let messages = messages.clone();
390	
391	        (State::Idle, Context {
392	            crop,
393	            aspect_ratio: props.aspect_ratio,
394	            zoom: props.zoom,
395	            min_zoom: props.min_zoom,
396	            max_zoom: props.max_zoom,
397	            disabled: props.disabled,
398	            circular: props.circular,
399	            flip: props.flip,
400	            drag_origin: None,
401	            drag_start_crop: None,
402	            focused_part: None,
403	            locale,
404	            messages,
405	            ids,
406	        })
407	    }
408	
409	    fn transition(
410	        state: &Self::State,
411	        event: &Self::Event,
412	        ctx: &Self::Context,
413	        _props: &Self::Props,
414	    ) -> Option<TransitionPlan<Self>> {
415	        // Focus/Blur always pass through.
416	        match event {
417	            Event::Focus { part } => {
418	                let p = *part;
419	                return Some(TransitionPlan::context_only(move |ctx| {
420	                    ctx.focused_part = Some(p);
421	                }));
422	            }
423	            Event::Blur { .. } => {
424	                return Some(TransitionPlan::context_only(|ctx| {
425	                    ctx.focused_part = None;
426	                }));
427	            }
428	            _ => {}
429	        }
430	
431	        if ctx.disabled { return None; }
432	
433	        match (state, event) {
434	            (State::Idle, Event::DragStart { x, y }) => {
435	                let x = *x; let y = *y;
436	                Some(TransitionPlan::to(State::Dragging).apply(move |ctx| {
437	                    ctx.drag_origin = Some((x, y));
438	                    ctx.drag_start_crop = Some(ctx.crop.get());
439	                }))
440	            }
441	
442	            (State::Dragging, Event::DragMove { x, y }) => {
443	                let x = *x; let y = *y;
444	                Some(TransitionPlan::context_only(move |ctx| {
445	                    if let (Some((ox, oy)), Some(ref start)) =
446	                        (ctx.drag_origin, &ctx.drag_start_crop)
447	                    {
448	                        let dx = x - ox;
449	                        let dy = y - oy;
450	                        let mut new_crop = *start;
451	                        new_crop.x = (start.x + dx).clamp(0.0, 1.0 - start.width);
452	                        new_crop.y = (start.y + dy).clamp(0.0, 1.0 - start.height);
453	                        ctx.crop.set(new_crop);
454	                    }
455	                }).with_effect(PendingEffect::new("announce-crop-moved", |ctx, _props, _send| {
456	                    // NOTE: The adapter should debounce/throttle this announcement
457	                    // (e.g., at most once per 500ms) to avoid flooding the screen reader
458	                    // with rapid-fire announcements during continuous pointer movement.
459	                    let platform = use_platform_effects();
460	                    platform.announce(&(ctx.messages.crop_moved)(&ctx.locale));
461	                    no_cleanup()
462	                })))
463	            }
464	
465	            (State::Dragging, Event::DragEnd) => {
466	                Some(TransitionPlan::to(State::Idle).apply(|ctx| {
467	                    ctx.drag_origin = None;
468	                    ctx.drag_start_crop = None;
469	                }))
470	            }
471	
472	            (State::Idle, Event::ResizeStart { handle, x, y }) => {
473	                let handle = *handle; let x = *x; let y = *y;
474	                Some(TransitionPlan::to(State::Resizing { handle }).apply(move |ctx| {
475	                    ctx.drag_origin = Some((x, y));
476	                    ctx.drag_start_crop = Some(ctx.crop.get());
477	                }))
478	            }
479	
480	            (State::Resizing { handle }, Event::ResizeMove { x, y }) => {
481	                let handle = *handle; let x = *x; let y = *y;
482	                Some(TransitionPlan::context_only(move |ctx| {
483	                    resize_crop_area(ctx, handle, x, y);
484	                }).with_effect(PendingEffect::new("announce-crop-resized", |ctx, _props, _send| {
485	                    // NOTE: The adapter should debounce/throttle this announcement
486	                    // (e.g., at most once per 500ms) to avoid flooding the screen reader
487	                    // with rapid-fire announcements during continuous pointer movement.
488	                    let platform = use_platform_effects();
489	                    platform.announce(&(ctx.messages.crop_resized)(&ctx.locale));
490	                    no_cleanup()
491	                })))
492	            }
493	
494	            (State::Resizing { .. }, Event::ResizeEnd) => {
495	                Some(TransitionPlan::to(State::Idle).apply(|ctx| {
496	                    ctx.drag_origin = None;
497	                    ctx.drag_start_crop = None;
498	                }))
499	            }
500	
501	            (_, Event::SetCropArea(area)) => {
502	                let area = *area;
503	                Some(TransitionPlan::context_only(move |ctx| {
504	                    ctx.crop.set(area);
505	                }))
506	            }
507	
508	            (_, Event::SetAspectRatio(ratio)) => {
509	                let ratio = *ratio;
510	                Some(TransitionPlan::context_only(move |ctx| {
511	                    ctx.aspect_ratio = ratio;
512	                    enforce_aspect_ratio(ctx);
513	                }))
514	            }
515	
516	            (_, Event::SetZoom(zoom)) => {
517	                let zoom = zoom.clamp(ctx.min_zoom, ctx.max_zoom);
518	                Some(TransitionPlan::context_only(move |ctx| {
519	                    ctx.zoom = zoom;
520	                }))
521	            }
522	
523	            (_, Event::SetRotation(rotation)) => {
524	                let rotation = *rotation;
525	                Some(TransitionPlan::context_only(move |ctx| {
526	                    let mut crop = ctx.crop.get();
527	                    crop.rotation = rotation;
528	                    ctx.crop.set(crop);
529	                }))
530	            }
531	
532	            (_, Event::FlipHorizontal) => {
533	                Some(TransitionPlan::context_only(|ctx| {
534	                    ctx.flip.horizontal = !ctx.flip.horizontal;
535	                }))
536	            }
537	
538	            (_, Event::FlipVertical) => {
539	                Some(TransitionPlan::context_only(|ctx| {
540	                    ctx.flip.vertical = !ctx.flip.vertical;
541	                }))
542	            }
543	
544	            (_, Event::Reset) => {
545	                Some(TransitionPlan::to(State::Idle).apply(|ctx| {
546	                    ctx.crop.set(CropArea::default());
547	                    ctx.zoom = 1.0;
548	                    ctx.flip = FlipState::default();
549	                    ctx.drag_origin = None;
550	                    ctx.drag_start_crop = None;
551	                }))
552	            }
553	
554	            (_, Event::NudgeCrop { dx, dy }) => {
555	                let dx = *dx; let dy = *dy;
556	                Some(TransitionPlan::context_only(move |ctx| {
557	                    let mut crop = ctx.crop.get();
558	                    crop.x = (crop.x + dx).clamp(0.0, 1.0 - crop.width);
559	                    crop.y = (crop.y + dy).clamp(0.0, 1.0 - crop.height);
560	                    ctx.crop.set(crop);
561	                }))
562	            }
563	
564	            _ => None,
565	        }
566	    }
567	
568	    fn connect<'a>(
569	        state: &'a Self::State,
570	        ctx: &'a Self::Context,
571	        props: &'a Self::Props,
572	        send: &'a dyn Fn(Self::Event),
573	    ) -> Self::Api<'a> {
574	        Api { state, ctx, props, send }
575	    }
576	}
