540	
541	    fn init(props: &Self::Props, env: &Env, messages: &Self::Messages) -> (State, Context) {
542	        let data = if let Some(data) = &props.data {
543	            Bindable::controlled(data.clone())
544	        } else {
545	            Bindable::uncontrolled(props.default_data.clone())
546	        };
547	
548	        let state = if data.get().is_empty() {
549	            State::Idle
550	        } else {
551	            State::Completed
552	        };
553	
554	        (
555	            state,
556	            Context {
557	                data,
558	                current_stroke: None,
559	                disabled: props.disabled,
560	                readonly: props.readonly,
561	                pen_color: props.pen_color.clone(),
562	                pen_width: props.pen_width,
563	                min_distance: props.min_distance,
564	                focused: false,
565	                locale: env.locale.clone(),
566	                messages: messages.clone(),
567	                ids: ComponentIds::from_id(&props.id),
568	            },
569	        )
570	    }
