572	    fn on_props_changed(old: &Props, new: &Props) -> Vec<Event> {
573	        assert_eq!(
574	            old.id, new.id,
575	            "signature_pad::Props.id must remain stable after init"
576	        );
577	
578	        let mut events = Vec::new();
579	
580	        if old.data != new.data {
581	            events.push(Event::SyncData);
582	        }
583	
584	        if old.disabled != new.disabled
585	            || old.readonly != new.readonly
586	            || old.pen_color != new.pen_color
587	            || old.pen_width != new.pen_width
588	            || old.min_distance != new.min_distance
589	        {
590	            events.push(Event::SyncProps);
591	        }
592	
593	        events
594	    }
595	
596	    fn transition(
597	        state: &Self::State,
598	        event: &Self::Event,
599	        ctx: &Self::Context,
600	        props: &Self::Props,
601	    ) -> Option<TransitionPlan<Self>> {
602	        // Focus/Blur and the prop-sync events always pass through, regardless of
603	        // disabled/read-only (prop sync must be able to re-enable the pad).
604	        match event {
605	            Event::Focus => {
606	                return Some(TransitionPlan::context_only(|ctx: &mut Context| {
607	                    ctx.focused = true;
608	                }));
609	            }
610	
611	            Event::Blur => {
612	                return Some(TransitionPlan::context_only(|ctx: &mut Context| {
613	                    ctx.focused = false;
614	                }));
615	            }
616	
617	            Event::SyncProps => {
618	                let disabled = props.disabled;
619	                let readonly = props.readonly;
620	                let pen_color = props.pen_color.clone();
621	                let pen_width = props.pen_width;
622	                let min_distance = props.min_distance;
623	
624	                // Becoming non-interactive mid-stroke must not strand the machine
625	                // in `Drawing` — the disabled/read-only gate below would then
626	                // reject the trailing `DrawEnd`/`Clear`, leaving an in-flight
627	                // stroke that could later commit stale. Cancel it and leave
628	                // `Drawing` (blank canvas -> `Idle`, otherwise `Completed`).
629	                let cancel_drawing = (disabled || readonly) && matches!(state, State::Drawing);
630	                let target = if cancel_drawing {
631	                    if ctx.data.pending().is_empty() {
632	                        State::Idle
633	                    } else {
634	                        State::Completed
635	                    }
636	                } else {
637	                    *state
638	                };
639	
640	                return Some(TransitionPlan::to(target).apply(move |ctx: &mut Context| {
641	                    ctx.disabled = disabled;
642	                    ctx.readonly = readonly;
643	                    ctx.pen_color = pen_color;
644	                    ctx.pen_width = pen_width;
645	                    ctx.min_distance = min_distance;
646	                    if cancel_drawing {
647	                        ctx.current_stroke = None;
648	                    }
649	                }));
650	            }
651	
652	            Event::SyncData => {
653	                let new_data = props.data.clone();
654	                // Emptiness after the sync: the new controlled value, or — when
655	                // dropping to uncontrolled — the retained local value.
656	
657	                let empty_after = if let Some(data) = &new_data {
658	                    data.is_empty()
659	                } else {
660	                    ctx.data.pending().is_empty()
661	                };
662	
663	                // Reconcile the displayed state with the synced data, but never
664	                // reorder an in-flight stroke.
665	                let plan = if matches!(state, State::Drawing) {
666	                    TransitionPlan::new()
667	                } else {
668	                    TransitionPlan::to(if empty_after {
669	                        State::Idle
670	                    } else {
671	                        State::Completed
672	                    })
673	                };
674	
675	                return Some(plan.apply(move |ctx: &mut Context| {
676	                    if let Some(data) = new_data {
677	                        ctx.data.set(data.clone());
678	                        ctx.data.sync_controlled(Some(data));
679	                    } else {
680	                        ctx.data.sync_controlled(None);
681	                    }
682	                }));
683	            }
684	
685	            _ => {}
686	        }
687	
688	        if ctx.disabled || ctx.readonly {
689	            return None;
690	        }
691	
692	        match (state, event) {
693	            // Start drawing: seed a new stroke and ask the adapter to wire up
694	            // the global pointer-drag listeners that feed DrawMove/DrawEnd.
695	            (State::Idle | State::Completed, Event::DrawStart { x, y, pressure }) => {
696	                let point = SignaturePoint {
697	                    x: *x,
698	                    y: *y,
699	                    pressure: *pressure,
700	                    timestamp: 0.0,
701	                };
702	
703	                Some(
704	                    TransitionPlan::to(State::Drawing)
705	                        .apply(move |ctx: &mut Context| {
706	                            ctx.current_stroke = Some(SignatureStroke {
707	                                points: vec![point],
708	                            });
709	                        })
710	                        .with_effect(PendingEffect::named(Effect::DrawingListeners)),
711	                )
712	            }
713	
714	            // Continue drawing: append the point only when it is at least
715	            // `min_distance` away from the previous one (cull jitter).
716	            (State::Drawing, Event::DrawMove { x, y, pressure }) => {
717	                let point = SignaturePoint {
718	                    x: *x,
719	                    y: *y,
720	                    pressure: *pressure,
721	                    timestamp: 0.0,
722	                };
723	
724	                Some(TransitionPlan::context_only(move |ctx: &mut Context| {
725	                    let min_distance = ctx.min_distance;
726	
727	                    if let Some(stroke) = ctx.current_stroke.as_mut()
728	                        && let Some(last) = stroke.points.last()
729	                    {
730	                        let dx = point.x - last.x;
731	                        let dy = point.y - last.y;
732	
733	                        if (dx * dx + dy * dy).sqrt() >= min_distance {
734	                            stroke.points.push(point);
735	                        }
736	                    }
737	                }))
738	            }
739	
740	            // End drawing: commit the in-flight stroke if it has enough points.
741	            // A stroke that is too short to commit (a stray tap) leaves the
742	            // signature unchanged, so the pad returns to `Idle` when the canvas
743	            // is still blank and only announces when a stroke is actually added.
744	            (State::Drawing, Event::DrawEnd) => {
745	                let commits = ctx
746	                    .current_stroke
747	                    .as_ref()
748	                    .is_some_and(|stroke| stroke.points.len() >= 2);
749	
750	                // Build on the *pending* (internal) data, not `get()`: in
751	                // controlled mode `get()` returns the stale parent value until it
752	                // round-trips through `on_data_change`, so reading it would drop
753	                // earlier un-synced strokes when several are drawn in quick
754	                // succession.
755	                let target = if commits || !ctx.data.pending().is_empty() {
756	                    State::Completed
757	                } else {
758	                    State::Idle
759	                };
760	
761	                let mut plan = TransitionPlan::to(target).apply(|ctx: &mut Context| {
762	                    if let Some(stroke) = ctx.current_stroke.take()
763	                        && stroke.points.len() >= 2
764	                    {
765	                        let mut data = ctx.data.pending().clone();
766	
767	                        data.strokes.push(stroke);
768	
769	                        ctx.data.set(data);
770	                    }
771	                });
772	
773	                if commits {
774	                    plan = plan
775	                        .with_effect(PendingEffect::named(Effect::AnnounceProvided))
776	                        .with_effect(data_change_effect());
777	                }
778	
779	                Some(plan)
780	            }
781	
782	            // Undo the last completed stroke. The post-pop emptiness — not the
783	            // stroke count — decides the target, so data carrying empty-stroke
784	            // entries can never strand the pad in `Completed` while it is blank.
785	            // Built on the pending working copy to preserve un-synced controlled
786	            // edits.
787	            (State::Completed, Event::Undo) => {
788	                let mut data = ctx.data.pending().clone();
789	                data.strokes.pop();
790	
791	                let target = if data.is_empty() {
792	                    State::Idle
793	                } else {
794	                    State::Completed
795	                };
796	
797	                Some(
798	                    TransitionPlan::to(target)
799	                        .apply(move |ctx: &mut Context| {
800	                            ctx.data.set(data);
801	                        })
802	                        .with_effect(data_change_effect()),
803	                )
804	            }
805	
806	            // Clear all strokes from any state.
807	            (_, Event::Clear) => {
808	                // Notify the parent only when there was something to clear, so a
809	                // clear on an already-blank pad does not emit a spurious change.
810	                let had_data = !ctx.data.pending().is_empty();
811	
812	                let mut plan = TransitionPlan::to(State::Idle)
813	                    .apply(|ctx: &mut Context| {
814	                        ctx.data.set(SignatureData::default());
815	                        ctx.current_stroke = None;
816	                    })
817	                    .with_effect(PendingEffect::named(Effect::AnnounceCleared));
818	
819	                if had_data {
820	                    plan = plan.with_effect(data_change_effect());
821	                }
822	
823	                Some(plan)
824	            }
825	
826	            _ => None,
827	        }
828	    }
