831	        state: &'a Self::State,
832	        ctx: &'a Self::Context,
833	        props: &'a Self::Props,
834	        send: &'a dyn Fn(Self::Event),
835	    ) -> Self::Api<'a> {
836	        Api {
837	            state,
838	            ctx,
839	            props,
840	            send,
841	        }
842	    }
