849	/// committed by the transition — in controlled mode `get()` would still return
850	/// the stale parent-owned value until it round-trips back through props.
851	fn data_change_effect() -> PendingEffect<Machine> {
852	    PendingEffect::new(Effect::DataChange, |ctx: &Context, props: &Props, _send| {
853	        if let Some(callback) = &props.on_data_change {
854	            callback(ctx.data.pending().clone());
855	        }
856	
857	        no_cleanup()
858	    })
859	}
