    }

    #[test]
    fn sync_props_mirrors_config_and_cancels_active_interaction() {
        let mut service = fresh_service(test_props());
        drop(service.send(Event::DragStart { x: 0.5, y: 0.5 }));
        assert_eq!(service.state(), &State::Dragging);

