                crop: CropArea {
                    rotation: 45.0,
                    ..CropArea::default()
                },
                ..Default::default()
            }
            .api()
            .rotation_slider_attrs()
        ));
    }

    #[test]
    fn snapshot_reset_trigger_enabled() {
        assert_snapshot!(snapshot_attrs(
