        // Build on the *pending* (internal) crop: in controlled mode `get()`
        // returns the stale parent value until it round-trips through
        // `on_crop_change`.
        let mut crop = *ctx.crop.pending();
        constrain_to_ratio(&mut crop, ratio);
        ctx.crop.set(crop);
    }
}

