fn sync_crop_enforces_active_aspect_ratio() {
    // A controlled crop pushed in by the parent must satisfy the active
    // ratio, just like init/SetCropArea do.
    let mut service = fresh_service(
        test_props()
            .crop(CropArea {
                x: 0.1,
                y: 0.1,
                width: 0.5,
                height: 0.5,
